arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty env vars are no longer treated as unset.
        // In .NET 8, GetEnvironmentVariable returned null for both unset AND empty.
        // In .NET 9, it returns null only when unset, and "" when explicitly empty.
        // Use HasEnvironmentVariable to check presence, then read the value.
        if (!Environment.HasEnvironmentVariable("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else
        {
            var val = Environment.GetEnvironmentVariable("MY_FLAG");
            Console.WriteLine($"MY_FLAG is set to: '{val}'");
        }
    }
}

